#!/bin/bash
# Generated By: Claude Code (Claude Opus 4.6)
# ponytail: curl loop, no deps beyond what's already on any dev box
COLLECTOR=${OTEL_COLLECTOR_URL:-http://localhost:4318}
TIMEOUT=${WAIT_TIMEOUT:-30}
elapsed=0
while ! curl -s -o /dev/null -w '' --connect-timeout 1 "$COLLECTOR" 2>/dev/null; do
  if [ "$elapsed" -ge "$TIMEOUT" ]; then
    echo "otel stack not ready after ${TIMEOUT}s" >&2
    exit 1
  fi
  sleep 1
  elapsed=$((elapsed + 1))
done
